import React, { useState, useEffect } from 'react';
import { Link, useSearchParams } from 'react-router-dom';

const SearchResults = () => {
  const [allTours, setAllTours] = useState([]);
  const [tours, setTours] = useState([]);
  const [loading, setLoading] = useState(true);
  const [searchParams] = useSearchParams();

  // 🔥 ФИЛЬТРАЦИЯ — точно работает с твоими данными
  const filterTours = (allTours) => {
    let filtered = [...allTours];
    const decodeParam = (param) => decodeURIComponent(param || '');

    // Страна
    const country = decodeParam(searchParams.get('country'));
    if (country) {
      filtered = filtered.filter(tour => tour.country === country);
    }

    // Город вылета
    const departure = decodeParam(searchParams.get('departure'));
    if (departure) {
      filtered = filtered.filter(tour => tour.departureCity === departure);
    }

    console.log('🎯 Найдено:', filtered.length, 'из', allTours.length);
    return filtered;
  };

  // 🔥 fetch('/tours.json') — из папки public
  useEffect(() => {
    fetch('/tours.json')
      .then(res => {
        if (!res.ok) throw new Error(`HTTP ${res.status}`);
        return res.json();
      })
      .then(data => {
        console.log('✅ Загружено из tours.json:', data.length, 'туров');
        console.log('Первый тур:', data[0]);
        setAllTours(data);
        setLoading(false);
      })
      .catch(err => {
        console.error('❌ tours.json ошибка:', err);
        setLoading(false);
      });
  }, []);

  // Фильтрация при изменении URL
  useEffect(() => {
    if (allTours.length > 0) {
      const filtered = filterTours(allTours);
      setTours(filtered);
    }
  }, [searchParams, allTours]);

  if (loading) {
    return (
      <div className="TVSearchResults" style={{ margin: "0 auto", width: "1296px" }}>
        <div style={{ padding: '40px', textAlign: 'center', color: '#666' }}>
          Загрузка туров из tours.json...
        </div>
      </div>
    );
  }

  return (
    <>
      <div className="TVSearchResults" style={{ margin: "0 auto", width: "1296px" }}>
        <div className="TVResultContentListWrapper">
          <div className="TVResultListView TVStyleTheme2">
            <div className="TVResultListViewBody TVResultContentList">
              
              {/* DEBUG */}
              <div style={{ 
                padding: '20px', 
                background: '#f8f9fa', 
                marginBottom: '20px',
                borderRadius: '8px'
              }}>
                <strong>🎯 Найдено: {tours.length} / {allTours.length}</strong>
                <br />
                <small>
                  Страна: "{decodeURIComponent(searchParams.get('country') || 'все')}" | 
                  Вылет: "{decodeURIComponent(searchParams.get('departure') || 'все')}"
                </small>
              </div>

              <div className="TVResultListViewList" id="tour-container">
                {tours.length === 0 ? (
                  <div style={{ padding: '60px 20px', textAlign: 'center', color: '#666' }}>
                    ❌ Туры не найдены по вашим критериям
                  </div>
                ) : (
                  tours.map((tour) => (
                    <div key={tour.id} className="TVResultListViewItem">
                      <div className="TVHotelResultItem">
                        <div className="TVHotelResulItemInfo">
                          <div className="TVHotelInfo">
                            <div className="TVResultItem">
                              {/* Изображение */}
                              <div className="TVResultItemImageWrapper TVSize-M">
                                <div 
                                  className="TVPhotoGalleryImage"
                                  style={{
                                    backgroundImage: `url('https://picsum.photos/400/200?random=${tour.id}')`,
                                    backgroundSize: "cover",
                                    height: "200px",
                                  }}
                                />
                              </div>
                              
                              <div className="TVResultItemBodyWrapper">
                                <div className="TVResultItemHeader">
                                  {/* Звезды */}
                                  <div className="TVResultItemPreTitle">
                                    <div className="stars-row">
                                      {[...Array(tour.stars)].map((_, i) => (
                                        <div key={i} className="TVHotelInfoStar" style={{color: '#ffc107'}}>
                                          ★
                                        </div>
                                      ))}
                                    </div>
                                  </div>
                                  
                                  {/* Название */}
                                  <div className="TVResultItemTitle">
                                    <Link className="TVHotelInfoTitleLink" to={`/tour/${tour.id}`}>
                                      {tour.title}
                                    </Link>
                                  </div>
                                  
                                  {/* Локация */}
                                  <div className="TVResultItemSubTitle">
                                    {tour.city}, {tour.country} | Вылет: {tour.departureCity}
                                  </div>
                                  
                                  {/* Даты и ночи */}
                                  <div style={{ color: '#666', fontSize: '14px', margin: '8px 0' }}>
                                    {tour.dates} • {tour.nights} ночей
                                  </div>
                                  
                                  {/* Цена */}
                                  <div className="TVResultItemPrice">
                                    <div className="TVResultItemNewPrice" style={{
                                      fontSize: '24px', 
                                      fontWeight: 'bold', 
                                      color: '#c50076'
                                    }}>
                                      {tour.price.toLocaleString()} ₽
                                    </div>
                                  </div>
                                </div>
                              </div>
                            </div>
                          </div>
                        </div>
                      </div>
                    </div>
                  ))
                )}
              </div>
            </div>
          </div>
        </div>
      </div>

      {/* Стили */}
      <style
        dangerouslySetInnerHTML={{
          __html: `
            .stars-row { display: flex; gap: 2px; margin-bottom: 8px; }
            .TVHotelInfoStar { font-size: 16px; }
            .TVHotelInfoTitleLink { 
              font-size: 18px; 
              font-weight: bold; 
              color: #333; 
              text-decoration: none; 
            }
            .TVHotelInfoTitleLink:hover { color: #c50076; }
          `
        }}
      />
    </>
  );
};

export default SearchResults;
